function App() {
  return (
    <div className="page">
      <header className="topbar" aria-label="navify header">
        <div className="topbar-accent" />

        <div className="topbar-inner">
          <div className="brand-group">
            <NavifyLogo />
            <span className="brand-title">Analytics for Core Lab</span>
          </div>

          <div className="actions-group">
            <button className="icon-button" aria-label="Apps">
              <AppLauncherIcon />
            </button>
            <button className="icon-button" aria-label="Notifications">
              <NotificationIcon />
            </button>
            <button className="icon-button" aria-label="Help">
              <span className="icon-help">?</span>
            </button>
            <button className="assistant-pill" aria-label="AI Companion">
              <span className="assistant-pill-glow" aria-hidden="true" />
              <span className="assistant-pill-label">AI Companion</span>
            </button>

            <span className="vertical-divider" aria-hidden="true" />

            <button className="profile-chip" aria-label="User profile">
              SR
            </button>

            <button className="roche-badge" aria-label="Roche">
              <RocheLogo />
            </button>
          </div>
        </div>

        <div className="topbar-shadow" />
      </header>

      <div className="layout-shell">
        <aside className="sidebar" aria-label="Primary navigation">
          <button className="sidebar-item selected" aria-current="page">
            <span className="sidebar-selection-bar" aria-hidden="true" />
            <span className="sidebar-icon-wrap">
              <HomeIcon />
            </span>
            <span className="sidebar-label">Home</span>
          </button>

          <button className="sidebar-item">
            <span className="sidebar-icon-wrap">
              <MonitorIcon />
            </span>
            <span className="sidebar-label">Overview</span>
          </button>

          <button className="sidebar-item">
            <span className="sidebar-icon-wrap">
              <HistogramIcon />
            </span>
            <span className="sidebar-label">Analysis</span>
          </button>

          <button className="sidebar-item">
            <span className="sidebar-icon-wrap">
              <TaskIcon />
            </span>
            <span className="sidebar-label">Reports</span>
          </button>
        </aside>

        <main className="content-placeholder" />
      </div>
    </div>
  );
}

export default App;
